#include "interface.h"

#include <cstdint>
#include <string>
#include <vector>

namespace {

bool matches_prefix(const std::string& s) {
  return s.size() >= 2 && s[0] == 'q' && s[1] <= 'm';
}

}  // namespace

uint64_t dictionary_prefix_weight_sum(
    const std::vector<std::string>& dictionary,
    const std::vector<uint16_t>& codes,
    const std::vector<uint32_t>& weights,
    int iters) {
  // Precompute filter for each dictionary entry (1 if matches prefix, 0 otherwise)
  std::vector<uint8_t> filter(dictionary.size());
  for (std::size_t i = 0; i < dictionary.size(); ++i) {
    filter[i] = matches_prefix(dictionary[i]) ? 1 : 0;
  }

  uint64_t sum = 0;
  const std::size_t N = codes.size();
  for (int iter = 0; iter < iters; ++iter) {
    sum = 0;
    for (std::size_t i = 0; i < N; ++i) {
      if (filter[codes[i]]) {
        sum += static_cast<uint64_t>(weights[i]);
      }
    }
  }
  return sum;
}
